import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / processing fee ---
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // --- Base premiums for main items (with 5 G fee added) ---
  it("single plain sword → premium 105 G (100 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("single plain amulet → premium 65 G (60 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("single plain staff → premium 85 G (80 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("single plain potion → premium 45 G (40 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 45 });
  });

  // --- Components base premiums ---
  it("single rune → premium 30 G (25 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 30 });
  });
  it("2 runes → premium 55 G (50 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 55 });
  });
  it("3 runes → premium 65 G (60 base block + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("4 runes → premium 105 G (100 base, no block, + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("7 runes → premium 180 G (175 base + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 180 });
  });

  // --- Alike components ---
  it("2 runes + 1 moonstone → premium 80 G (75 base, no block: different types, + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 80 });
  });
  it("3 runes + 3 moonstones → premium 125 G (120 base, two separate blocks, + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 125 });
  });

  // --- Cursed surcharge ---
  it("newcomer with cursed sword (steel, ench 3), 0 years, no prior contract → premium 165 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });

  // --- High enchantment threshold ---
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (+30 G)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword at enchantment 5 → both surcharges apply");

  // --- Loyalty discount threshold ---
  it.todo("customer with exactly 2 years → loyalty discount applies (-20% of policy base)");

  // --- Modifier scope on multi-item policies ---
  it.todo("policy with cursed sword + plain amulet → 210 G before further modifiers and fee (cursed surcharge applies only to cursed item's base premium)");

  // --- Rounding in MHPCO's favor (premium up) ---
  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3), 0 years, no prior contract → premium 165 G");
  it.todo("long-standing customer's second contract: 3 years, cursed sword ench 7 → premium 160 G");

  // --- Quote: unknown item type ---
  it.todo("quote with unknown item type → CLI exits non-zero with stderr error, no results on stdout");

  // --- Claim: basic deductible & standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (no enchantment/material), damage 200 G → payout 100 G");

  // --- Claim: enchantment ≥ 8 clause ---
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then -100)");

  // --- Claim: dragon material clause ---
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full then -100)");

  // --- Claim: both clauses, 50% wins ---
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then -100)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies, then deductible)");

  // --- Claim: deductible per damage event (multiple items) ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("two-sword policy: dragon attack damages both swords → each entry has its own deductible");
  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("policy of sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (premium-modifiers don't raise cap) → cap 2000 G based on unmodified insurance value");
  it.todo("policy of sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword (cap 2000 G), two successive 1500 G claims → first payout 1400 G remaining 600; second payout 600 remaining 0");

  // --- Rounding payout down ---
  it.todo("payout calculation that yields 350.5 G → final payout 350 G (rounded down)");

  // --- Claim: error cases ---
  it.todo("claim references item not in policy → CLI exits non-zero with stderr error");
  it.todo("claim damage with negative amount → CLI exits non-zero with stderr error");

  // --- CLI integration ---
  it.todo("CLI schema example: customer 5 years, amulet quote then fire claim of 200 G");
});

