export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;
const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremium = (item: Item): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const existing = groups.get(item.type) ?? [];
    existing.push(item);
    groups.set(item.type, existing);
  }
  return groups;
};

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremium(item), 0);

const groupTotal = (type: string, group: Item[]): number => {
  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
    return COMPONENT_BLOCK_PRICE;
  }
  return sumBasePremiums(group);
};

const policyBase = (items: Item[]): number => {
  let total = 0;
  for (const [type, group] of groupByType(items)) {
    total += groupTotal(type, group);
  }
  return total;
};

const cursedSurcharge = (items: Item[]): number =>
  items.reduce(
    (sum, item) =>
      sum + (item.cursed ? basePremium(item) * CURSED_SURCHARGE_RATE : 0),
    0,
  );

const quotePremium = (items: Item[]): number => {
  const base = policyBase(items);
  const surcharges = cursedSurcharge(items) + base * FIRST_INSURANCE_RATE;
  return Math.ceil(base + surcharges) + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  const step = scenario.steps[0] as QuoteStep;
  return { results: [{ premium: quotePremium(step.items) }] };
};

