interface Policy {
  items: Item[];
  remainingCap: number;
}

const processQuote = (
  step: QuoteStep,
  customer: Customer,
  quoteIndex: number,
  policies: Map<number, Policy>,
  stepIndex: number,
): QuoteResult => {
  policies.set(stepIndex, {
    items: step.items,
    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
  });
  return { premium: quotePremium(step.items, customer, quoteIndex) };
};

const processClaim = (
  step: ClaimStep,
  policies: Map<number, Policy>,
): ClaimResult => {
  const policy = policies.get(step.policy) as Policy;
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
    0,
  );
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const processScenario = (scenario: Scenario): ScenarioOutput => {
  let quoteCount = 0;
  const policies = new Map<number, Policy>();
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      return processQuote(
        step,
        scenario.customer,
        quoteCount++,
        policies,
        index,
      );
    }
    return processClaim(step, policies);
  });
  return { results };
};

