186	  quoteIndex: number;
187	  stepIndex: number;
188	}
189	
190	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
191	  state.policies.set(state.stepIndex, {
192	    items: step.items,
193	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
194	  });
195	  const premium = quotePremium(step.items, state.customer, state.quoteIndex);
196	  state.quoteIndex += 1;
197	  return { premium };
198	};
199	
200	const reimbursementRate = (item: Item): number =>
201	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
202	    ? HIGH_ENCHANTMENT_CLAIM_RATE
203	    : 1;
204	
205	const damagePayout = (damage: Damage, items: Item[]): number => {
206	  const item = items.find((it) => it.type === damage.itemType) as Item;
207	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
208	};
209	
210	const countBy = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
211	  const counts = new Map<string, number>();
212	  for (const item of items) {
213	    const k = key(item);
214	    counts.set(k, (counts.get(k) ?? 0) + 1);
215	  }
216	  return counts;
217	};
218	
219	const validateDamages = (damages: Damage[], items: Item[]): void => {
220	  const itemCounts = countBy(items, (item) => item.type);
221	  const damageCounts = countBy(damages, (damage) => damage.itemType);
222	  for (const [type, count] of damageCounts) {
223	    if (count > (itemCounts.get(type) ?? 0)) {
224	      throw new Error(
225	        `claim damages exceed policy coverage for itemType ${type}`,
226	      );
227	    }
228	  }
229	};
230	
231	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
232	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
233	
234	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
235	  const policy = state.policies.get(step.policy) as Policy;
236	  validateDamages(step.incident.damages, policy.items);
237	  const rawPayout = sumDamagePayouts(step.incident.damages, policy.items);
238	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
239	  policy.remainingCap -= payout;
240	  return { payout, remainingCap: policy.remainingCap };
241	};
242	
243	const processStep = (step: Step, state: ScenarioState): StepResult =>
244	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
245	
246	export const processScenario = (scenario: Scenario): ScenarioOutput => {
247	  const state: ScenarioState = {
248	    customer: scenario.customer,
249	    policies: new Map<number, Policy>(),
250	    quoteIndex: 0,
251	    stepIndex: 0,
252	  };
253	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
254	    state.stepIndex = stepIndex;
255	    return processStep(step, state);
256	  });
257	  return { results };
258	};

